"use client"

import { AdminLayout } from "@/components/admin-layout"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Trash2, Edit2, Plus } from "lucide-react"
import { useState } from "react"

interface Rule {
  id: string
  engine: "COMP" | "DOM" | "ARV" | "PROFIT"
  key: string
  value: number | boolean
  unit?: "%" | "days" | "count" | "miles"
  description: string
  locked: boolean // client-safe
}


export default function RulesPage() {
  const [rules, setRules] = useState<Rule[]>([
    {
      id: "1",
      category: "Profit Requirements",
      rule: "Minimum Profit Margin",
      value: "15%",
      description: "Properties must show at least 15% profit margin",
    },
    {
      id: "2",
      category: "Profit Requirements",
      rule: "Profit Calculation",
      value: "ARV - Purchase - Repairs",
      description: "Profit = After Repair Value minus Purchase Price and estimated repairs",
    },
    {
      id: "3",
      category: "DOM Gating Rules",
      rule: "Maximum DOM Threshold",
      value: "60 days",
      description: "All comparable properties must have sold within 60 days on market",
    },
    {
      id: "4",
      category: "DOM Gating Rules",
      rule: "COMP Count Requirement",
      value: "Minimum 3",
      description: "Property must have at least 3 comparable sales in the market",
    },
  ])

  const [isCreating, setIsCreating] = useState(false)
  const [editingId, setEditingId] = useState<string | null>(null)
  const [formData, setFormData] = useState({
    category: "",
    rule: "",
    value: "",
    description: "",
  })

  const handleCreate = () => {
    if (!formData.category || !formData.rule || !formData.value) return

    const newRule: Rule = {
      id: Date.now().toString(),
      ...formData,
    }

    setRules([...rules, newRule])
    setFormData({ category: "", rule: "", value: "", description: "" })
    setIsCreating(false)
  }

  const handleUpdate = () => {
    if (!editingId || !formData.category || !formData.rule || !formData.value) return

    setRules(rules.map((rule) => (rule.id === editingId ? { ...rule, ...formData } : rule)))
    setEditingId(null)
    setFormData({ category: "", rule: "", value: "", description: "" })
  }

  const handleDelete = (id: string) => {
    setRules(rules.filter((rule) => rule.id !== id))
  }

  const handleEdit = (rule: Rule) => {
    setEditingId(rule.id)
    setFormData({
      category: rule.category,
      rule: rule.rule,
      value: rule.value,
      description: rule.description,
    })
  }

  const groupedRules = rules.reduce(
    (acc, rule) => {
      const existing = acc.find((g) => g.category === rule.category)
      if (existing) {
        existing.items.push(rule)
      } else {
        acc.push({ category: rule.category, items: [rule] })
      }
      return acc
    },
    [] as { category: string; items: Rule[] }[],
  )

  return (
    <AdminLayout>
      <div className="p-8 space-y-6">
        <div className="flex items-center justify-between">
          <div className="space-y-2">
            <h1 className="text-4xl font-bold text-foreground">Underwriting Rules</h1>
            <p className="text-muted-foreground">Create and manage deal evaluation criteria</p>
          </div>
          <Button
            onClick={() => {
              setIsCreating(!isCreating)
              setEditingId(null)
              setFormData({ category: "", rule: "", value: "", description: "" })
            }}
            className="gap-2 bg-primary hover:bg-primary/90"
          >
            <Plus className="w-4 h-4" />
            New Rule
          </Button>
        </div>

        {(isCreating || editingId) && (
          <Card className="border-primary/30 bg-primary/5">
            <CardHeader>
              <CardTitle>{editingId ? "Edit Rule" : "Create New Rule"}</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="category" className="text-foreground font-medium">
                    Category
                  </Label>
                  <Input
                    id="category"
                    value={formData.category}
                    onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                    placeholder="e.g., Profit Requirements"
                    className="bg-background"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="rule" className="text-foreground font-medium">
                    Rule Name
                  </Label>
                  <Input
                    id="rule"
                    value={formData.rule}
                    onChange={(e) => setFormData({ ...formData, rule: e.target.value })}
                    placeholder="e.g., Minimum Profit Margin"
                    className="bg-background"
                  />
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="value" className="text-foreground font-medium">
                  Value
                </Label>
                <Input
                  id="value"
                  value={formData.value}
                  onChange={(e) => setFormData({ ...formData, value: e.target.value })}
                  placeholder="e.g., 15%"
                  className="bg-background"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="description" className="text-foreground font-medium">
                  Description
                </Label>
                <textarea
                  id="description"
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  placeholder="Explain this rule..."
                  className="w-full px-3 py-2 rounded-lg border border-border bg-background text-foreground resize-none"
                  rows={3}
                />
              </div>
              <div className="flex gap-2 justify-end">
                <Button
                  variant="outline"
                  onClick={() => {
                    setIsCreating(false)
                    setEditingId(null)
                    setFormData({ category: "", rule: "", value: "", description: "" })
                  }}
                >
                  Cancel
                </Button>
                <Button onClick={editingId ? handleUpdate : handleCreate} className="bg-primary hover:bg-primary/90">
                  {editingId ? "Update" : "Create"}
                </Button>
              </div>
            </CardContent>
          </Card>
        )}

        <div className="space-y-6">
          {groupedRules.map((group) => (
            <Card key={group.category}>
              <CardHeader>
                <CardTitle>{group.category}</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  {group.items.map((item) => (
                    <div
                      key={item.id}
                      className="p-4 rounded-lg border border-border hover:bg-muted/50 transition-colors"
                    >
                      <div className="flex items-start justify-between mb-2">
                        <p className="font-semibold text-foreground">{item.rule}</p>
                        <div className="flex items-center gap-2">
                          <span className="px-3 py-1 rounded-full bg-primary/20 text-primary text-sm font-medium">
                            {item.value}
                          </span>
                          <button
                            onClick={() => handleEdit(item)}
                            className="text-primary hover:text-primary/80 transition-colors"
                            title="Edit"
                          >
                            <Edit2 className="w-4 h-4" />
                          </button>
                          <button
                            onClick={() => handleDelete(item.id)}
                            className="text-destructive hover:text-destructive/80 transition-colors"
                            title="Delete"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                      <p className="text-sm text-muted-foreground">{item.description}</p>
                    </div>
                  ))}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      </div>
    </AdminLayout>
  )
}
